// Build the Claude request for the in-app "Assistant" tab. Body from the app:
// { messages: [{role:'user'|'assistant', text}], ... } — the browser sends the
// full visible conversation (already stripped of any tool-call detail on the
// app's own side; here we also never echo mcp_tool_use/mcp_tool_result blocks
// back into history, so the chat only ever carries plain text turns).
//
// Uses Anthropic's native MCP connector (mcp_servers + tools:[mcp_toolset]) so
// Claude calls the do-or-wait Cloud Run MCP server directly, server-side — no
// manual tool-call loop needed here. This is the whole point of building the
// chat panel ourselves instead of using Claude Desktop/claude.ai conversation
// mode: Justin controls what's rendered, and the API only ever returns text +
// (separate, ignorable) mcp_tool_use/mcp_tool_result blocks — nothing forces
// a step-by-step tool-call narration into the UI.
const b = $json.body || {};
const msgs = Array.isArray(b.messages) ? b.messages : [];
const today = new Date().toISOString().slice(0, 10);

const sys = 'You are an internal operations assistant for Justin Cho at Cubework, ' +
  'embedded in his "Do or Wait" sales-ops app. Today is ' + today + '.\n\n' +
  'You have live tools, via the do-or-wait MCP connector, covering Tasks, Leads, ' +
  'Notes, Outreach, Property Outreach, Availability, Pricing, Rate Bands, ' +
  'Renewals, and Roster. Use a tool whenever the question needs live or specific ' +
  'data (a lead\'s status, what is open at a location, logging a call, checking ' +
  'follow-ups, etc). Answer directly, with no tool call, for general or ' +
  'how-does-this-work questions.\n\n' +
  'Never state a specific fact, a name, a number, a status, an availability, ' +
  'unless a tool result actually confirms it or the user just told you directly ' +
  'in this conversation. Do not guess or invent details. When you take a write ' +
  'action, such as logging an update, changing a stage, or creating something, ' +
  'briefly confirm in plain language what you did.\n\n' +
  'Keep replies short and direct. Plain language. No bullet-point lists unless ' +
  'the user is actually asking for a list of several things. No dash characters, ' +
  'em dash or en dash, joining clauses, use a period or comma instead.';

const anthMsgs = msgs
  .filter(m => m && m.text)
  .map(m => ({
    role: m.role === 'assistant' ? 'assistant' : 'user',
    content: [{ type: 'text', text: String(m.text) }]
  }));

if (!anthMsgs.length) throw new Error('No messages provided');

// SETUP (do this after import, directly in the n8n UI, NOT in this committed
// file): replace the line below with a literal string, e.g.
//   const mcpUrl = 'https://your-service.run.app/mcp/your-token';
// This n8n instance's own "Environment variables" panel is a paid feature we
// don't have, so $env.DOW_MCP_URL will not resolve here. Hardcoding the URL
// directly in this node keeps it out of the committed/exported JSON (it only
// lives in your private n8n database) and sidesteps the paywall entirely.
// See n8n/24_assistant_chat.README.md for the full explanation.
const mcpUrl = ($env.DOW_MCP_URL || '').trim();
if (!mcpUrl) throw new Error('Set mcpUrl directly in this node, see the comment above — DOW_MCP_URL is not available as an env var on this instance.');

// PROMPT CACHING (2026-07-10): the system prompt + tool definitions (from the
// MCP connector) are identical on every single turn, and were being fully
// reprocessed and re-billed at full price every message. This one top-level
// field turns on Anthropic's "automatic caching" — it finds the repeated
// prefix (tools, then system, then messages, in that order) and reuses it,
// moving the cache point forward itself as the conversation grows. Cache
// reads are ~10% of normal input price and process faster than a full
// re-read, so this cuts both cost and latency on every turn after the first
// in a session (default 5-minute cache lifetime, refreshed free on each hit).
const requestBody = {
  model: 'claude-sonnet-4-6',
  max_tokens: 2000,
  cache_control: { type: 'ephemeral' },
  system: sys,
  messages: anthMsgs,
  mcp_servers: [
    { type: 'url', url: mcpUrl, name: 'do-or-wait' }
  ],
  tools: [
    { type: 'mcp_toolset', mcp_server_name: 'do-or-wait' }
  ]
};

return [{ json: { requestBody } }];

// Extract ONLY the plain text for the app to show — this is the whole point:
// mcp_tool_use / mcp_tool_result blocks are deliberately dropped here so the
// browser never even receives a play-by-play of tool calls, let alone renders
// one. toolsUsed is returned separately as an optional, opt-in debug signal
// (the app can choose to show a small "used: get_lead, update_lead" chip, or
// ignore it entirely and show nothing beyond the reply).
const res = $json;

if (res.error || res.type === 'error') {
  const msg = (res.error && res.error.message) || res.message || 'Unknown Claude API error';
  return [{ json: { ok: false, error: msg } }];
}

const blocks = Array.isArray(res.content) ? res.content : [];
const reply = blocks.filter(x => x && x.type === 'text').map(x => x.text).join('\n\n').trim();
const toolsUsed = Array.from(new Set(
  blocks.filter(x => x && x.type === 'mcp_tool_use').map(x => x.name)
));
const usage = res.usage || {};

if (!reply) {
  return [{ json: { ok: false, error: 'Claude returned no text content (stop_reason: ' + (res.stop_reason || 'unknown') + ')' } }];
}

return [{ json: { ok: true, reply, toolsUsed, stopReason: res.stop_reason || null, cacheRead: usage.cache_read_input_tokens || 0, cacheWrite: usage.cache_creation_input_tokens || 0 } }];
